EVENTS = json.loads(RAW)

# Fix timestamps and clean fields for the consumer schema
for ev in EVENTS:
    ev["timestamp"] = TS
    # Ensure required fields the consumer expects
    if "source_type" not in ev:
        # Infer source_type from topic
        topic = ev.get("topic", "raw-logs")
        mapping = {
            "network-events": "network",
            "process-events": "process",
            "security-events": "windows_security",
            "raw-logs": "syslog",
        }
        ev["source_type"] = mapping.get(topic, "syslog")
    if "user_id" not in ev:
        ev["user_id"] = ""


def rpk_produce(topic: str, payload: str):
    r = subprocess.run(
        ["docker", "exec", "-i", "clif-redpanda01", "rpk", "topic", "produce", topic,
         "--key", str(uuid.uuid4())[:8]],
        input=(payload + "\n").encode(), capture_output=True, timeout=15,
    )
    return r.returncode == 0


def ch_query(sql: str):
    r = subprocess.run(
        ["docker", "exec", "clif-clickhouse01", "clickhouse-client", "-q", sql],
        capture_output=True, text=True, timeout=10,
    )
    return r.stdout.strip()


# ─────────────────────────────────────────────────────────────────────────────
if __name__ == "__main__":
    # Count by label
    labels = {}
    topics = {}
    for ev in EVENTS:
        labels[ev["label"]] = labels.get(ev["label"], 0) + 1
        topics[ev["topic"]] = topics.get(ev["topic"], 0) + 1

    print("=" * 70)
    print("CLIF Pipeline - 120 Mixed Log Injection Test")
    print("=" * 70)
    print(f"\nTotal events: {len(EVENTS)}")
    for lbl, cnt in sorted(labels.items()):
        print(f"  {lbl:10s}: {cnt}")
    print(f"\nBy topic:")
    for t, cnt in sorted(topics.items()):
        print(f"  {t:20s}: {cnt}")

    # Baseline
    base = int(ch_query("SELECT count() FROM clif_logs.triage_scores") or "0")
    print(f"\n[1/3] Baseline triage_scores: {base}")

    # Produce
    print(f"\n[2/3] Producing {len(EVENTS)} events...")
    ok_count = 0
    fail_count = 0
    for i, ev in enumerate(EVENTS):
        topic = ev.pop("topic")
        label = ev.pop("label")
        # Build clean event (remove non-schema fields)
        event = {k: v for k, v in ev.items() if k not in ("dst_ip",)}
        success = rpk_produce(topic, json.dumps(event))
        status = "OK" if success else "FAIL"
        if success:
            ok_count += 1
        else:
            fail_count += 1
        if (i + 1) % 20 == 0 or not success:
            print(f"  [{i+1:3d}/{len(EVENTS)}] {label:10s} {topic:20s} [{status}]")

    print(f"\n  Sent: {ok_count} OK, {fail_count} FAIL")

    # Wait for triage
    print(f"\n[3/3] Waiting for triage to process...")
    for wait_round in range(6):
        time.sleep(10)
        current = int(ch_query("SELECT count() FROM clif_logs.triage_scores") or "0")
        delta = current - base
        print(f"  +{wait_round*10+10}s: {current} triage_scores (+{delta} new)")
        if delta >= ok_count:
            break

    # Summary
    current = int(ch_query("SELECT count() FROM clif_logs.triage_scores") or "0")
    delta = current - base
    escalated = ch_query(
        f"SELECT count() FROM clif_logs.triage_scores "
        f"WHERE action = 'escalate' AND timestamp >= now() - INTERVAL 5 MINUTE"
    )
    monitored = ch_query(
        f"SELECT count() FROM clif_logs.triage_scores "
        f"WHERE action = 'monitor' AND timestamp >= now() - INTERVAL 5 MINUTE"
    )
    discarded = ch_query(
        f"SELECT count() FROM clif_logs.triage_scores "
        f"WHERE action = 'discard' AND timestamp >= now() - INTERVAL 5 MINUTE"
    )

    print(f"\n{'=' * 70}")
    print(f"STAGE 1 RESULTS (Vector -> Triage -> ClickHouse)")
    print(f"{'=' * 70}")
    print(f"  Events sent:       {ok_count}")
    print(f"  Triage scored:     {delta}")
    print(f"  Escalated:         {escalated}")
    print(f"  Monitored:         {monitored}")
    print(f"  Discarded:         {discarded}")
    print(f"{'=' * 70}")
    print(f"\nStage 1 complete. Hunter is stopped.")
    print(f"Run 'docker start lancedb-service && docker start clif-hunter-agent'")
    print(f"Then check: docker exec clif-clickhouse01 clickhouse-client --format PrettyCompact \\")
    print(f"  -q \"SELECT hostname, confidence, finding_type FROM clif_logs.hunter_investigations ORDER BY started_at DESC LIMIT 30\"")
